const body = $input.first().json.body || $input.first().json;
const links = body.links || [];
if (!Array.isArray(links) || links.length === 0) throw new Error('links is required');
const raw_text = body.raw_text || '';
const run_id = 'n8n-smoke-' + new Date().toISOString().replace(/[-:.TZ]/g, '').slice(0, 14);
const items = links.map((url) => ({
  source_type: url.includes('x.com') || url.includes('twitter') ? 'x' : 'web',
  source_url: url,
  title: 'Local smoke source',
  transcript: raw_text,
  language: body.language || 'zh+en',
  meta: { chars: raw_text.length, method: 'local_smoke_raw_text' }
}));
return [{ json: { ok: true, run_id, items, need_materials: raw_text.length < 300 ? [{ source_url: links[0], missing: '正文不足300字' }] : [] } }];
